    /**
     * Validate URL and return safe version.
     */
    try {
      const parsed = new URL(url);

      // Only allow http and https
      if (!['http:', 'https:'].includes(parsed.protocol)) {
        console.warn('Invalid protocol:', parsed.protocol);
        return '#';
      }

      return parsed.href;
    } catch {
      console.error('Invalid URL:', url);
